@pytest.mark.pre_alloc_mutable
def test_gas_cost_mem_seg(
    state_test: StateTestFiller,
    pre: Alloc,
    tx_data_hex: str,
    expected_post: dict,
) -> None:
    """Ori Pomerantz qbzzt1@gmail.com."""
    coinbase = Address("0x2adc25665018aa1fe0e6bc666dac8fc2697ff9ba")
    sender = EOA(
        key=0x40AC0FC28C27E961EE46EC43355A094DE205856EDBD4654CF2577C2608D4EC1E
    )

    env = Environment(
        fee_recipient=coinbase,
        number=1,
        timestamp=1000,
        prev_randao=0x20000,
        base_fee_per_gas=10,
        gas_limit=100000000,
    )

    pre[sender] = Account(balance=0xBA1A9CE0BA1A9CE)
    # Source: LLL
    # {
    #   ;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
    #   ; Initialization
    #
    #   ; Variables (0x20 byte wide)
    #   (def 'gasB4             0x000)  ; Before the action being measured
    #   (def 'gasAfter          0x020)  ; After the action being measured
    #
    #   (def 'afterVars         0x100)  ; Memory after the variables,
    #                                   ; safe to copy into
    #
    #   ; Understand CALLDATA. It is four bytes of function
    #   ; selector (irrelevant) followed by 32 byte words
    #   ; of the parameters
    #   (def 'opcode     $4 )
    #   (def 'length     $36)
    #   (def 'expectedCost $68)
    #
    #   ; NOP for if statements
    #   (def 'NOP     0)
    #
    #   ;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;
    #   ; Run the operation
    #
    #   ; SHA3
    #   (if (= opcode 0x20) {
    #       [gasB4]    (gas)
    #       (sha3 0 length)
    #       [gasAfter] (gas)
    #   } NOP)
    # ... (70 more lines)
    contract = pre.deploy_contract(
        code=(
            Op.JUMPI(
                pc=Op.PUSH2[0x11],
                condition=Op.EQ(Op.CALLDATALOAD(offset=0x4), 0x20),
            )
            + Op.POP(0x0)
            + Op.JUMP(pc=Op.PUSH2[0x21])
            + Op.JUMPDEST
            + Op.MSTORE(offset=0x0, value=Op.GAS)
            + Op.POP(Op.SHA3(offset=0x0, size=Op.CALLDATALOAD(offset=0x24)))
            + Op.MSTORE(offset=0x20, value=Op.GAS)
            + Op.JUMPDEST
            + Op.JUMPI(
                pc=Op.PUSH2[0x33],
                condition=Op.EQ(Op.CALLDATALOAD(offset=0x4), 0x37),
            )
            + Op.POP(0x0)
            + Op.JUMP(pc=Op.PUSH2[0x45])
            + Op.JUMPDEST
            + Op.MSTORE(offset=0x0, value=Op.GAS)
            + Op.CALLDATACOPY(
                dest_offset=0x100,
                offset=0x0,
                size=Op.CALLDATALOAD(offset=0x24),
            )
            + Op.MSTORE(offset=0x20, value=Op.GAS)
            + Op.JUMPDEST
            + Op.JUMPI(
                pc=Op.PUSH2[0x57],
                condition=Op.EQ(Op.CALLDATALOAD(offset=0x4), 0x39),
            )
            + Op.POP(0x0)
            + Op.JUMP(pc=Op.PUSH2[0x69])
            + Op.JUMPDEST
            + Op.MSTORE(offset=0x0, value=Op.GAS)
            + Op.CODECOPY(
                dest_offset=0x100,
                offset=0x0,
                size=Op.CALLDATALOAD(offset=0x24),
            )
            + Op.MSTORE(offset=0x20, value=Op.GAS)
            + Op.JUMPDEST
            + Op.JUMPI(
                pc=Op.PUSH2[0x7B],
                condition=Op.EQ(Op.CALLDATALOAD(offset=0x4), 0xA0),
            )
            + Op.POP(0x0)
            + Op.JUMP(pc=Op.PUSH2[0x8A])
            + Op.JUMPDEST
            + Op.MSTORE(offset=0x0, value=Op.GAS)
            + Op.LOG0(offset=0x0, size=Op.CALLDATALOAD(offset=0x24))
            + Op.MSTORE(offset=0x20, value=Op.GAS)
            + Op.JUMPDEST
            + Op.JUMPI(
                pc=Op.PUSH2[0x9C],
                condition=Op.EQ(Op.CALLDATALOAD(offset=0x4), 0xA1),
            )
            + Op.POP(0x0)
            + Op.JUMP(pc=Op.PUSH2[0xAD])
            + Op.JUMPDEST
            + Op.MSTORE(offset=0x0, value=Op.GAS)
            + Op.LOG1(
                offset=0x0, size=Op.CALLDATALOAD(offset=0x24), topic_1=0x1
            )
            + Op.MSTORE(offset=0x20, value=Op.GAS)
            + Op.JUMPDEST
            + Op.JUMPI(
                pc=Op.PUSH2[0xBF],
                condition=Op.EQ(Op.CALLDATALOAD(offset=0x4), 0xA2),
            )
            + Op.POP(0x0)
            + Op.JUMP(pc=Op.PUSH2[0xD2])
            + Op.JUMPDEST
            + Op.MSTORE(offset=0x0, value=Op.GAS)
            + Op.LOG2(
                offset=0x0,
                size=Op.CALLDATALOAD(offset=0x24),
                topic_1=0x1,
                topic_2=0x2,
            )
            + Op.MSTORE(offset=0x20, value=Op.GAS)
            + Op.JUMPDEST
            + Op.JUMPI(
                pc=Op.PUSH2[0xE4],
                condition=Op.EQ(Op.CALLDATALOAD(offset=0x4), 0xA3),
            )
            + Op.POP(0x0)
            + Op.JUMP(pc=Op.PUSH2[0xF9])
            + Op.JUMPDEST
            + Op.MSTORE(offset=0x0, value=Op.GAS)
            + Op.LOG3(
                offset=0x0,
                size=Op.CALLDATALOAD(offset=0x24),
                topic_1=0x1,
                topic_2=0x2,
                topic_3=0x3,
            )
            + Op.MSTORE(offset=0x20, value=Op.GAS)
            + Op.JUMPDEST
            + Op.JUMPI(
                pc=0x10B,
                condition=Op.EQ(Op.CALLDATALOAD(offset=0x4), 0xA4),
            )
            + Op.POP(0x0)
            + Op.JUMP(pc=0x122)
            + Op.JUMPDEST
            + Op.MSTORE(offset=0x0, value=Op.GAS)
            + Op.LOG4(
                offset=0x0,
                size=Op.CALLDATALOAD(offset=0x24),
                topic_1=0x1,
                topic_2=0x2,
                topic_3=0x3,
                topic_4=0x4,
            )
            + Op.MSTORE(offset=0x20, value=Op.GAS)
            + Op.JUMPDEST
            + Op.SSTORE(
                key=0x0,
                value=Op.SUB(
                    Op.SUB(Op.MLOAD(offset=0x0), Op.MLOAD(offset=0x20)),
                    Op.CALLDATALOAD(offset=0x44),
                ),
            )
            + Op.STOP
        ),
        storage={0x0: 0x60A7},
        balance=0xBA1A9CE0BA1A9CE,
        nonce=0,
        address=Address("0x727437e50af8535411157a4aca154c81d72baad4"),  # noqa: E501
    )

    tx_data = bytes.fromhex(tx_data_hex) if tx_data_hex else b""

    tx = Transaction(
        sender=sender,
        to=contract,
        data=tx_data,
        gas_limit=16777216,
        value=1,
    )

    post = expected_post

    state_test(env=env, pre=pre, post=post, tx=tx)


